package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.validation.*;import java.math.*;import java.util.*;public class RoomServiceImpl implements RoomService{private final RoomDao dao;private final RoomValidator validator;private final AuditLogDao audit;public RoomServiceImpl(){this(new RoomDaoImpl(),new RoomValidator(),new AuditLogDaoImpl());}public RoomServiceImpl(RoomDao d,RoomValidator v,AuditLogDao a){dao=d;validator=v;audit=a;}public Page<Room>listRooms(PageRequest p,Long d,String t,String s){try{return dao.findAll(p,d,t,s);}catch(Exception e){return new Page<>(List.of(),p.getPageNumber(),p.getPageSize(),0);}}public Optional<Room>getRoom(Long id){try{return dao.findById(id);}catch(Exception e){return Optional.empty();}}public ServiceResult<Long>createRoom(RoomForm f,AuditContext a){ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{Room r=from(f);if(dao.existsByRoomNumber(r.getRoomNumber()))return failL(ServiceResult.Status.DUPLICATE,"Room number already exists");long id=dao.create(r);event("ROOM_CREATED",id,a);return ServiceResult.success("Room created",id);}catch(Exception e){return failL(ServiceResult.Status.SYSTEM_ERROR,"Room service unavailable");}}public ServiceResult<Void>updateRoom(RoomForm f,AuditContext a){ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{Room r=from(f);r.setRoomId(f.getRoomId());if(dao.existsByRoomNumberExcludingId(r.getRoomNumber(),r.getRoomId()))return fail(ServiceResult.Status.DUPLICATE,"Room number already exists");dao.update(r);event("ROOM_UPDATED",r.getRoomId(),a);return ServiceResult.success("Room updated",null);}catch(Exception e){return fail(ServiceResult.Status.SYSTEM_ERROR,"Room service unavailable");}}public ServiceResult<Void>updateRoomStatus(Long id,String action,AuditContext a){try{String st=Map.of("activate","ACTIVE","deactivate","INACTIVE","maintenance","MAINTENANCE").get(action);if(st==null)return fail(ServiceResult.Status.VALIDATION_ERROR,"Invalid action");if(!"ACTIVE".equals(st)&&dao.hasOccupiedBeds(id)){event("ROOM_STATUS_CHANGE_BLOCKED",id,a);return fail(ServiceResult.Status.CONFLICT,"Occupied rooms cannot be disabled");}dao.updateStatus(id,st);event("ROOM_STATUS_CHANGED",id,a);return ServiceResult.success("Room status updated",null);}catch(Exception e){return fail(ServiceResult.Status.SYSTEM_ERROR,"Room service unavailable");}}private Room from(RoomForm f){Room r=new Room();r.setRoomNumber(f.getRoomNumber().trim().toUpperCase());r.setRoomType(f.getRoomType().toUpperCase());r.setFloorNumber(Integer.valueOf(f.getFloorNumber()));r.setDepartmentId(f.getDepartmentId());r.setDailyRate(new BigDecimal(f.getDailyRate()));r.setStatus(f.getStatus().toUpperCase());return r;}private void event(String e,Long id,AuditContext a){try{audit.recordEvent(e,a==null?null:a.userId(),"ROOM",id,a==null?null:a.ipAddress(),a==null?null:a.userAgent());}catch(Exception ignored){}}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}}
